SourceCode.Declaration:
/// <summary>
/// JSON contract returned by <c>SIMSStartSqlExecutionService.executeSql</c>.
/// </summary>
[DataContractAttribute]
public class SIMSStartSqlExecuteResponseContract
{
    boolean success;
    str     message;
    int     rowsAffected;
    str     correlationId;
}

Method.Source:
[DataMemberAttribute('Success')]
public boolean parmSuccess(boolean _success = success)
{
    success = _success;
    return success;
}

[DataMemberAttribute('Message')]
public str parmMessage(str _message = message)
{
    message = _message;
    return message;
}

[DataMemberAttribute('RowsAffected')]
public int parmRowsAffected(int _rowsAffected = rowsAffected)
{
    rowsAffected = _rowsAffected;
    return rowsAffected;
}

[DataMemberAttribute('CorrelationId')]
public str parmCorrelationId(str _correlationId = correlationId)
{
    correlationId = _correlationId;
    return correlationId;
}
